<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body {font-family:Arial,sans-serif;margin:20px;max-width:800px;}
  h2 {margin-top:30px;}
  .form-group {margin-bottom:10px;}
  label {display:inline-block;width:80px;}
  input, select, button {padding:5px;}
  #form-error {color:red;margin-top:5px;}
  #expense-list {margin-top:20px;border-top:1px solid #ccc;}
  .expense {display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #eee;}
  .expense span {margin-right:10px;}
  .exp-del {background:#e74c3c;color:#fff;border:none;padding:3px 6px;cursor:pointer;}
  #summary {margin-top:20px;}
  .cat-total {margin-right:15px;}
  .filters {margin-top:20px;}
  .filters select, .filters input {margin-right:10px;}
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<!-- Entry Form -->
<form id="expense-form">
  <div class="form-group">
    <label for="amount">Amount:</label>
    <input type="number" id="amount" step="0.01" required>
  </div>
  <div class="form-group">
    <label for="category">Category:</label>
    <select id="category">
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>
  </div>
  <div class="form-group">
    <label for="date">Date:</label>
    <input type="date" id="date" required>
  </div>
  <div class="form-group">
    <label for="note">Note:</label>
    <input type="text" id="note" placeholder="optional">
  </div>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<!-- Filters -->
<div class="filters">
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">all</option>
    <option value="groceries">groceries</option>
    <option value="transport">transport</option>
    <option value="bills">bills</option>
    <option value="fun">fun</option>
  </select>

  <label for="filter-from">From:</label>
  <input type="date" id="filter-from">

  <label for="filter-to">To:</label>
  <input type="date" id="filter-to">
</div>

<!-- Expense List -->
<h2>Expenses</h2>
<div id="expense-list"></div>

<!-- Summary -->
<div id="summary">
  <strong>Total: $<span id="total">0.00</span></strong>
  <div id="category-summary">
    <span class="cat-total" data-cat="groceries">groceries: $0.00</span>
    <span class="cat-total" data-cat="transport">transport: $0.00</span>
    <span class="cat-total" data-cat="bills">bills: $0.00</span>
    <span class="cat-total" data-cat="fun">fun: $0.00</span>
  </div>
</div>

<script>
(() => {
  const categories = ['groceries','transport','bills','fun'];
  const storageKey = 'expenses';
  let expenses = [];

  // DOM Elements
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');
  const expenseList = document.getElementById('expense-list');
  const totalSpan = document.getElementById('total');
  const filterCat = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // Load from localStorage
  function loadExpenses() {
    const data = localStorage.getItem(storageKey);
    if (data) {
      try { expenses = JSON.parse(data); }
      catch { expenses = []; }
    }
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(storageKey, JSON.stringify(expenses));
  }

  // Render expense rows
  function renderExpenses() {
    expenseList.innerHTML = '';
    // newest first (already stored that way)
    expenses.forEach(exp => {
      const row = document.createElement('div');
      row.className = 'expense';
      row.dataset.id = exp.id;
      row.dataset.category = exp.category;
      row.dataset.date = exp.date; // ISO string (yyyy-mm-dd)

      const amountSpan = document.createElement('span');
      amountSpan.className = 'exp-amount';
      amountSpan.textContent = `$${Number(exp.amount).toFixed(2)}`;

      const catSpan = document.createElement('span');
      catSpan.className = 'exp-category';
      catSpan.textContent = exp.category;

      const dateSpan = document.createElement('span');
      dateSpan.className = 'exp-date';
      dateSpan.textContent = exp.date;

      const noteSpan = document.createElement('span');
      noteSpan.className = 'exp-note';
      noteSpan.textContent = exp.note ? `(${exp.note})` : '';

      const delBtn = document.createElement('button');
      delBtn.className = 'exp-del';
      delBtn.textContent = 'Delete';

      row.appendChild(amountSpan);
      row.appendChild(catSpan);
      row.appendChild(dateSpan);
      row.appendChild(noteSpan);
      row.appendChild(delBtn);
      expenseList.appendChild(row);
    });
    applyFilters(); // ensure visibility matches filters
  }

  // Update totals based on visible rows
  function updateTotals() {
    let total = 0;
    const catTotals = {groceries:0, transport:0, bills:0, fun:0};

    const rows = expenseList.querySelectorAll('.expense');
    rows.forEach(row => {
      if (row.style.display === 'none') return;
      const amount = parseFloat(row.querySelector('.exp-amount').textContent.slice(1));
      const cat = row.dataset.category;
      total += amount;
      if (catTotals.hasOwnProperty(cat)) catTotals[cat] += amount;
    });

    totalSpan.textContent = total.toFixed(2);
    // Update per-category summary
    const catElems = document.querySelectorAll('.cat-total');
    catElems.forEach(el => {
      const cat = el.dataset.cat;
      el.textContent = `${cat}: $${catTotals[cat].toFixed(2)}`;
    });
  }

  // Apply filters to rows
  function applyFilters() {
    const selectedCat = filterCat.value;
    const fromDate = filterFrom.value;
    const toDate = filterTo.value;

    const rows = expenseList.querySelectorAll('.expense');
    rows.forEach(row => {
      const rowCat = row.dataset.category;
      const rowDate = row.dataset.date; // yyyy-mm-dd

      let show = true;
      if (selectedCat !== 'all' && rowCat !== selectedCat) show = false;
      if (fromDate && rowDate < fromDate) show = false;
      if (toDate && rowDate > toDate) show = false;

      row.style.display = show ? '' : 'none';
    });
    updateTotals();
  }

  // Add expense handler
  form.addEventListener('submit', e => {
    e.preventDefault();
    const amountVal = amountInput.value.trim();
    const dateVal = dateInput.value.trim();

    const amountNum = parseFloat(amountVal);
    if (!amountVal || isNaN(amountNum) || amountNum <= 0) {
      formError.textContent = 'Please enter a positive amount.';
      return;
    }
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return;
    }

    // Valid
    formError.textContent = '';
    const newExp = {
      id: Date.now().toString() + Math.random().toString(36).substr(2,5),
      amount: amountNum,
      category: categorySelect.value,
      date: dateVal,
      note: noteInput.value.trim()
    };
    expenses.unshift(newExp); // newest first
    saveExpenses();
    renderExpenses();
    amountInput.value = '';
    // keep other fields as is
  });

  // Delete handler (event delegation)
  expenseList.addEventListener('click', e => {
    if (e.target.classList.contains('exp-del')) {
      const row = e.target.closest('.expense');
      const id = row.dataset.id;
      expenses = expenses.filter(exp => exp.id !== id);
      saveExpenses();
      renderExpenses();
    }
  });

  // Filter change handlers
  filterCat.addEventListener('change', applyFilters);
  filterFrom.addEventListener('change', applyFilters);
  filterTo.addEventListener('change', applyFilters);

  // Initial load
  loadExpenses();
  renderExpenses();
})();
</script>

</body>
</html>
